use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
struct Player {
    name: String,
    score: i32,
    items: Vec<String>,
}

fn main() {
    let p1 = Player {
        name: String::from("Rustacean"),
        score: 1000,
        items: vec!["Sword".to_string(), "Shield".to_string()],
    };

    // Serialize to JSON String
    let json = serde_json::to_string(&p1).unwrap();
    println!("JSON: {}", json);

    // Deserialize back to Struct
    let p2: Player = serde_json::from_str(&json).unwrap();
    println!("Struct: {:?}", p2);
}

use serde_json::{json, Value};

fn main() {
    // Constructing dynamic JSON
    let data = json!({
        "status": "ok",
        "code": 200,
        "payload": {
            "features": ["fast", "safe"],
            "users": null
        }
    });

    println!("Created JSON: {}", data);

    // Accessing fields dynamically
    let feature = data["payload"]["features"][0].as_str().unwrap();
    println!("First feature: {}", feature);

    // Parsing unknown JSON
    let raw = r#"{"name": "Unknown", "age": 99}"#;
    let v: Value = serde_json::from_str(raw).unwrap();
    println!("Parsed Name: {}", v["name"]);
}

use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
#[serde(rename_all = "camelCase")] // Converts first_name -> firstName
struct UserConfig {
    first_name: String,

    #[serde(rename = "lname")] // Manual override
    last_name: String,

    #[serde(default)] // Use false if missing
    is_admin: bool,

    #[serde(skip_serializing)] // Secret, never export
    password_hash: String,
}

fn main() {
    let json_input = r#"{
        "firstName": "Alice",
        "lname": "Smith"
    }"#;

    let user: UserConfig = serde_json::from_str(json_input).unwrap();
    println!("Deserialized: {:?}", user);
    // Notice is_admin is false (default)

    let json_output = serde_json::to_string(&user).unwrap();
    println!("Serialized: {}", json_output);
    // Notice password_hash is missing
}

use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
struct Pagination {
    page: u32,
    limit: u32,
}

#[derive(Serialize, Deserialize, Debug)]
struct UserQuery {
    filter: String,

    #[serde(flatten)]
    pagination: Pagination,

    // Capture any extra fields in a HashMap!
    #[serde(flatten)]
    extra: std::collections::HashMap<String, serde_json::Value>
}

fn main() {
    let raw = r#"{
        "filter": "active",
        "page": 1,
        "limit": 10,
        "sort": "desc" 
    }"#;

    let q: UserQuery = serde_json::from_str(raw).unwrap();
    println!("Struct: {:?}", q);
    // Notice "sort" ended up in the 'extra' map
    // Notice 'page' and 'limit' populated the inner Pagination struct
}

use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Debug)]
#[serde(tag = "type")] // Internal tagging
enum Message {
    #[serde(rename = "text")]
    Text { content: String },

    #[serde(rename = "image")]
    Image { url: String, width: u32 },
}

fn main() {
    let msg = Message::Image { 
        url: "img.png".into(), 
        width: 1024 
    };

    // Output: {"type":"image","url":"img.png","width":1024}
    println!("{}", serde_json::to_string(&msg).unwrap());

    let json = r#"{"type": "text", "content": "Hello!"}"#;
    let decoded: Message = serde_json::from_str(json).unwrap();
    println!("{:?}", decoded);
}

use serde::{Serialize, Serializer, Deserialize, Deserializer};

fn serialize_as_string<S>(val: &i32, serializer: S) -> Result<S::Ok, S::Error>
where S: Serializer {
    serializer.serialize_str(&val.to_string())
}

fn deserialize_from_string<'de, D>(deserializer: D) -> Result<i32, D::Error>
where D: Deserializer<'de> {
    let s: String = Deserialize::deserialize(deserializer)?;
    s.parse().map_err(serde::de::Error::custom)
}

#[derive(Serialize, Deserialize, Debug)]
struct Data {
    // Treat this int as a string in JSON
    #[serde(serialize_with = "serialize_as_string")]
    #[serde(deserialize_with = "deserialize_from_string")]
    number: i32,
}

fn main() {
    let d = Data { number: 42 };
    let json = serde_json::to_string(&d).unwrap();

    // Output: {"number":"42"} (it's a string!)
    println!("{}", json);
}

